2343 /// Find a constant NewC that has property:
2344 ///   shuffle(NewC, ShMask) = C
2345 /// Returns nullptr if such a constant does not exist e.g. ShMask=<0,0> C=<1,2>
2346 ///
2347 /// A 1-to-1 mapping is not required. Example:
2348 /// ShMask = <1,1,2,2> and C = <5,5,6,6> --> NewC = <poison,5,6,poison>
2349 Constant *InstCombinerImpl::unshuffleConstant(ArrayRef<int> ShMask, Constant *C,
2350                                               VectorType *NewCTy) {
2351   if (isa<ScalableVectorType>(NewCTy)) {
2352     Constant *Splat = C->getSplatValue();
2353     if (!Splat)
2354       return nullptr;
2355     return ConstantVector::getSplat(NewCTy->getElementCount(), Splat);
2356   }
2357 
2358   if (cast<FixedVectorType>(NewCTy)->getNumElements() >
2359       cast<FixedVectorType>(C->getType())->getNumElements())
2360     return nullptr;
2361 
2362   unsigned NewCNumElts = cast<FixedVectorType>(NewCTy)->getNumElements();
2363   PoisonValue *PoisonScalar = PoisonValue::get(C->getType()->getScalarType());
2364   SmallVector<Constant *, 16> NewVecC(NewCNumElts, PoisonScalar);
2365   unsigned NumElts = cast<FixedVectorType>(C->getType())->getNumElements();
2366   for (unsigned I = 0; I < NumElts; ++I) {
2367     Constant *CElt = C->getAggregateElement(I);
2368     if (ShMask[I] >= 0) {
2369       assert(ShMask[I] < (int)NumElts && "Not expecting narrowing shuffle");
2370       Constant *NewCElt = NewVecC[ShMask[I]];
2371       // Bail out if:
2372       // 1. The constant vector contains a constant expression.
2373       // 2. The shuffle needs an element of the constant vector that can't
2374       //    be mapped to a new constant vector.
2375       // 3. This is a widening shuffle that copies elements of V1 into the
2376       //    extended elements (extending with poison is allowed).
2377       if (!CElt || (!isa<PoisonValue>(NewCElt) && NewCElt != CElt) ||
2378           I >= NewCNumElts)
2379         return nullptr;
2380       NewVecC[ShMask[I]] = CElt;
2381     }
2382   }
2383   return ConstantVector::get(NewVecC);
2384 }
