2399 static Instruction *foldSpliceBinOp(BinaryOperator &Inst,
2400                                     InstCombiner::BuilderTy &Builder) {
2401   Value *LHS = Inst.getOperand(0), *RHS = Inst.getOperand(1);
2402   auto CreateBinOpSplice = [&](Value *X, Value *Y, Value *Offset) {
2403     Value *V = Builder.CreateBinOp(Inst.getOpcode(), X, Y, Inst.getName());
2404     if (auto *BO = dyn_cast<BinaryOperator>(V))
2405       BO->copyIRFlags(&Inst);
2406     Module *M = Inst.getModule();
2407     Function *F = Intrinsic::getOrInsertDeclaration(M, SpliceID, V->getType());
2408     return CallInst::Create(F, {V, PoisonValue::get(V->getType()), Offset});
2409   };
2410   Value *V1, *V2, *Offset;
2411   if (match(LHS,
2412             m_Intrinsic<SpliceID>(m_Value(V1), m_Poison(), m_Value(Offset)))) {
2413     // Op(splice(V1, poison, offset), splice(V2, poison, offset))
2414     // -> splice(Op(V1, V2), poison, offset)
2415     if (match(RHS, m_Intrinsic<SpliceID>(m_Value(V2), m_Poison(),
2416                                          m_Specific(Offset))) &&
2417         (LHS->hasOneUse() || RHS->hasOneUse() ||
2418          (LHS == RHS && LHS->hasNUses(2))))
2419       return CreateBinOpSplice(V1, V2, Offset);
2420 
2421     // Op(splice(V1, poison, offset), RHSSplat)
2422     // -> splice(Op(V1, RHSSplat), poison, offset)
2423     if (LHS->hasOneUse() && isSplatValue(RHS))
2424       return CreateBinOpSplice(V1, RHS, Offset);
2425   }
2426   // Op(LHSSplat, splice(V2, poison, offset))
2427   // -> splice(Op(LHSSplat, V2), poison, offset)
2428   else if (isSplatValue(LHS) &&
2429            match(RHS, m_OneUse(m_Intrinsic<SpliceID>(m_Value(V2), m_Poison(),
2430                                                      m_Value(Offset)))))
2431     return CreateBinOpSplice(LHS, V2, Offset);
2432 
2433   // TODO: Fold binops of the form
2434   // Op(splice(poison, V1, offset), splice(poison, V2, offset))
