2440 Instruction *InstCombinerImpl::foldVectorBinop(BinaryOperator &Inst) {
2441   if (!isa<VectorType>(Inst.getType()))
2442     return nullptr;
2443 
2444   BinaryOperator::BinaryOps Opcode = Inst.getOpcode();
2445   Value *LHS = Inst.getOperand(0), *RHS = Inst.getOperand(1);
2446   assert(cast<VectorType>(LHS->getType())->getElementCount() ==
2447          cast<VectorType>(Inst.getType())->getElementCount());
2448   assert(cast<VectorType>(RHS->getType())->getElementCount() ==
2449          cast<VectorType>(Inst.getType())->getElementCount());
2450 
2451   auto foldConstantsThroughSubVectorInsertSplat =
2452       [&](Value *MaybeSubVector, Value *MaybeSplat,
2453           bool SplatLHS) -> Instruction * {
2454     Value *Idx;
2455     Constant *Splat, *SubVector, *Dest;
2456     if (!match(MaybeSplat, m_ConstantSplat(m_Constant(Splat))) ||
2457         !match(MaybeSubVector,
2458                m_VectorInsert(m_Constant(Dest), m_Constant(SubVector),
2459                               m_Value(Idx))))
2460       return nullptr;
2461     SubVector =
2462         constantFoldBinOpWithSplat(Opcode, SubVector, Splat, SplatLHS, DL);
2463     Dest = constantFoldBinOpWithSplat(Opcode, Dest, Splat, SplatLHS, DL);
2464     if (!SubVector || !Dest)
2465       return nullptr;
2466     auto *InsertVector =
2467         Builder.CreateInsertVector(Dest->getType(), Dest, SubVector, Idx);
2468     return replaceInstUsesWith(Inst, InsertVector);
2469   };
2470 
2471   // If one operand is a constant splat and the other operand is a
2472   // `vector.insert` where both the destination and subvector are constant,
2473   // apply the operation to both the destination and subvector, returning a new
2474   // constant `vector.insert`. This helps constant folding for scalable vectors.
2475   if (Instruction *Folded = foldConstantsThroughSubVectorInsertSplat(
2476           /*MaybeSubVector=*/LHS, /*MaybeSplat=*/RHS, /*SplatLHS=*/false))
2477     return Folded;
2478   if (Instruction *Folded = foldConstantsThroughSubVectorInsertSplat(
2479           /*MaybeSubVector=*/RHS, /*MaybeSplat=*/LHS, /*SplatLHS=*/true))
2480     return Folded;
