2000       // icmp eq zext(bool), 0 will fold to !bool.
2001       if (isa<ZExtInst>(InVal) &&
2002           cast<ZExtInst>(InVal)->getSrcTy()->isIntOrIntVectorTy(1) &&
2003           match(&I,
2004                 m_SpecificICmp(ICmpInst::ICMP_EQ, m_Specific(PN), m_Zero())))
